/** Configuration for a token bucket rate limiter. */
export interface RateLimiterConfig {
  /** Maximum number of tokens (requests) allowed in the window. */
  readonly maxTokens: number;
  /** Time window in milliseconds over which tokens refill. */
  readonly windowMs: number;
  /** Whether to queue requests that exceed the limit (true) or reject them (false). */
  readonly queueExcess: boolean;
  /** Maximum number of requests to queue before rejecting. Only used when queueExcess is true. */
  readonly maxQueueDepth: number;
}

/** Error thrown when a rate-limited request is rejected. */
export class RateLimitExceededError extends Error {
  constructor(
    public readonly exchangeId: string,
    public readonly retryAfterMs: number,
  ) {
    super(`Rate limit exceeded for ${exchangeId}. Retry after ${retryAfterMs}ms.`);
    this.name = 'RateLimitExceededError';
  }
}

interface QueuedRequest {
  resolve: () => void;
  reject: (error: Error) => void;
}

/**
 * Token bucket rate limiter for exchange REST API requests.
 *
 * Tokens refill linearly over the configured window. When tokens are exhausted,
 * requests are either queued (up to maxQueueDepth) or immediately rejected
 * based on configuration.
 */
export class RateLimiter {
  private tokens: number;
  private lastRefillTimestamp: number;
  private readonly queue: QueuedRequest[] = [];
  private drainTimer: ReturnType<typeof setTimeout> | undefined;
  private disposed = false;

  constructor(
    private readonly exchangeId: string,
    private readonly config: RateLimiterConfig,
    private readonly now: () => number = Date.now,
  ) {
    this.tokens = config.maxTokens;
    this.lastRefillTimestamp = this.now();
  }

  /** Acquire a token. Resolves when a token is available. Rejects if queue is full or limiter is disposed. */
  async acquire(): Promise<void> {
    if (this.disposed) {
      throw new Error(`RateLimiter for ${this.exchangeId} is disposed`);
    }

    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return;
    }

    if (!this.config.queueExcess) {
      throw new RateLimitExceededError(this.exchangeId, this.msUntilNextToken());
    }

    if (this.queue.length >= this.config.maxQueueDepth) {
      throw new RateLimitExceededError(this.exchangeId, this.msUntilNextToken());
    }

    return new Promise<void>((resolve, reject) => {
      this.queue.push({ resolve, reject });
      this.scheduleDrain();
    });
  }

  /** Try to acquire a token without waiting. Returns true if a token was consumed. */
  tryAcquire(): boolean {
    if (this.disposed) return false;
    this.refill();
    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  /** Get the number of available tokens. */
  getAvailableTokens(): number {
    this.refill();
    return Math.floor(this.tokens);
  }

  /** Get the number of queued requests. */
  getQueueDepth(): number {
    return this.queue.length;
  }

  /** Milliseconds until the next token becomes available. */
  msUntilNextToken(): number {
    if (this.tokens >= 1) return 0;
    const msPerToken = this.config.windowMs / this.config.maxTokens;
    const deficit = 1 - this.tokens;
    return Math.ceil(deficit * msPerToken);
  }

  /** Reset the limiter to full capacity and clear the queue. */
  reset(): void {
    this.tokens = this.config.maxTokens;
    this.lastRefillTimestamp = this.now();
    this.drainQueue();
  }

  /** Dispose the limiter, rejecting all queued requests. */
  dispose(): void {
    this.disposed = true;
    if (this.drainTimer !== undefined) {
      clearTimeout(this.drainTimer);
      this.drainTimer = undefined;
    }
    for (const request of this.queue) {
      request.reject(new Error(`RateLimiter for ${this.exchangeId} disposed`));
    }
    this.queue.length = 0;
  }

  private refill(): void {
    const currentTime = this.now();
    const elapsed = currentTime - this.lastRefillTimestamp;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.config.windowMs) * this.config.maxTokens;
    this.tokens = Math.min(this.config.maxTokens, this.tokens + tokensToAdd);
    this.lastRefillTimestamp = currentTime;
  }

  private scheduleDrain(): void {
    if (this.drainTimer !== undefined) return;
    const delayMs = this.msUntilNextToken();
    this.drainTimer = setTimeout(() => {
      this.drainTimer = undefined;
      this.drainQueue();
    }, Math.max(1, delayMs));
  }

  private drainQueue(): void {
    this.refill();
    while (this.queue.length > 0 && this.tokens >= 1) {
      this.tokens -= 1;
      const request = this.queue.shift();
      if (request) {
        request.resolve();
      }
    }
    if (this.queue.length > 0 && !this.disposed) {
      this.scheduleDrain();
    }
  }
}

