  coinbase: { maxTokens: 30, windowMs: 1_000, queueExcess: true, maxQueueDepth: 50 },
  bybit: { maxTokens: 120, windowMs: 1_000, queueExcess: true, maxQueueDepth: 50 },
  okx: { maxTokens: 20, windowMs: 2_000, queueExcess: true, maxQueueDepth: 30 },
